function startCounter(t){const e=+t.getAttribute("data-target");let r=0;const n=performance.now(),o=a=>{const c=a-n,i=Math.min(c/2e3,1);r=i*e,t.innerText=Math.ceil(r),i<1?requestAnimationFrame(o):t.innerText=e};requestAnimationFrame(o)}document.addEventListener("DOMContentLoaded",()=>{setTimeout(()=>{const t=document.querySelectorAll(".temp3-counter-card h3"),e=new IntersectionObserver((t,e)=>{t.forEach(t=>{t.isIntersecting&&(startCounter(t.target),e.unobserve(t.target))})},{threshold:.1});t.forEach(t=>{e.observe(t)})},100)}),window.addEventListener("load",()=>{setTimeout(()=>{document.querySelectorAll(".temp3-counter-card h3").forEach(t=>{"0"===t.innerText&&t.getAttribute("data-target")&&startCounter(t)})},500)});